 * Inserts folder selection entries with a value of "MANUAL" for folders that were explicitly configured,
 * or "AUTOMATIC" for folders that were not configured (null).
 */
public class AccountSettingsUpgraderTo54 implements SettingsUpgrader {
    private static final String FOLDER_SELECTION_MANUAL = "MANUAL";
    private static final String FOLDER_SELECTION_AUTOMATIC = "AUTOMATIC";

    @Override
    public void upgrade(Map<String, Object> settings) {
        setFolderSelection(settings, "archiveFolderName", "archiveFolderSelection");
        setFolderSelection(settings, "draftsFolderName", "draftsFolderSelection");
        setFolderSelection(settings, "sentFolderName", "sentFolderSelection");
        setFolderSelection(settings, "spamFolderName", "spamFolderSelection");
        setFolderSelection(settings, "trashFolderName", "trashFolderSelection");
    }

    private void setFolderSelection(Map<String, Object> settings, String folderNameKey, String folderSelectionKey) {
        String folderName = (String) settings.get(folderNameKey);
        // If a folder was explicitly configured (not null), use MANUAL selection
        // Otherwise, use AUTOMATIC selection to allow auto-detection
        if (folderName != null) {
            settings.put(folderSelectionKey, FOLDER_SELECTION_MANUAL);
        } else {
            settings.put(folderSelectionKey, FOLDER_SELECTION_AUTOMATIC);
        }
    }
}"}

